INSERT INTO cornucopia_record (user_id, draw_date, draw_count, free_used)
VALUES (#{userId}, #{drawDate}, #{drawCount}, #{freeUsed})
ON DUPLICATE KEY UPDATE draw_count = #{drawCount}, free_used = #{freeUsed}
